162	### 1.6 Full Machine Implementation
163	
164	```rust
165	/// Machine for the DateRangeField component.
166	pub struct Machine;
167	
168	impl ars_core::Machine for Machine {
169	    type State = State;
170	    type Event = Event;
171	    type Context = Context;
172	    type Props = Props;
173	    type Messages = Messages;
174	    type Api<'a> = Api<'a>;
175	
176	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
177	        let locale = env.locale.clone();
178	        let ctx = Context {
179	            value: match &props.value {
180	                Some(v) => Bindable::controlled(v.clone()),
181	                None => Bindable::uncontrolled(props.default_value.clone()),
182	            },
183	            active_field: None,
184	            min: props.min.clone(),
185	            max: props.max.clone(),
186	            messages: messages.clone(),
187	            locale,
188	            disabled: props.disabled,
189	            readonly: props.readonly,
190	            required: props.required,
191	            name: props.name.clone(),
192	            start_name: props.start_name.clone(),
193	            end_name: props.end_name.clone(),
194	            ids: ComponentIds::from_id(&props.id),
195	            has_description: false,
196	            has_error_message: false,
197	            force_leading_zeros: props.force_leading_zeros,
198	        };
199	        (State::Idle, ctx)
200	    }
201	
202	    fn transition(
203	        state: &Self::State,
204	        event: &Self::Event,
205	        ctx: &Self::Context,
206	        _props: &Self::Props,
207	    ) -> Option<TransitionPlan<Self>> {
208	        if is_disabled(ctx) { return None; }
209	
210	        match event {
211	            Event::FocusStart => {
212	                Some(TransitionPlan::to(State::StartFocused).apply(|ctx| {
213	                    ctx.active_field = Some(ActiveField::Start);
214	                }))
215	            }
216	
217	            Event::FocusEnd => {
218	                Some(TransitionPlan::to(State::EndFocused).apply(|ctx| {
219	                    ctx.active_field = Some(ActiveField::End);
220	                }))
221	            }
222	
223	            Event::BlurAll => {
224	                Some(TransitionPlan::to(State::Idle).apply(|ctx| {
225	                    ctx.active_field = None;
226	                }))
227	            }
228	
229	            Event::SetRange(range) => {
230	                let range = range.clone();
231	                Some(TransitionPlan::context_only(move |ctx| {
232	                    ctx.value.set(range);
233	                }))
234	            }
235	
236	            Event::StartValueChange(date) => {
237	                let date = date.clone();
238	                Some(TransitionPlan::context_only(move |ctx| {
239	                    match (&date, ctx.value.get().as_ref().map(|r| &r.end)) {
240	                        (Some(start), Some(end)) => {
241	                            ctx.value.set(Some(DateRange::normalized(
242	                                start.clone(), end.clone(),
243	                            )));
244	                        }
245	                        (Some(start), None) => {
246	                            // Only start set; store partial (no complete range yet)
247	                            // Range will complete when end is also set.
248	                        }
249	                        (None, _) => {
250	                            ctx.value.set(None);
251	                        }
252	                    }
253	                }))
254	            }
255	
256	            Event::EndValueChange(date) => {
257	                let date = date.clone();
258	                Some(TransitionPlan::context_only(move |ctx| {
259	                    match (ctx.value.get().as_ref().map(|r| &r.start), &date) {
260	                        (Some(start), Some(end)) => {
261	                            ctx.value.set(Some(DateRange::normalized(
262	                                start.clone(), end.clone(),
263	                            )));
264	                        }
265	                        (None, Some(end)) => {
266	                            // Only end set; store partial.
267	                        }
268	                        (_, None) => {
269	                            ctx.value.set(None);
270	                        }
271	                    }
272	                }))
273	            }
274	        }
275	    }
276	}
277	```
