279	### 1.7 Connect / API
280	
281	```rust
282	#[derive(ComponentPart)]
283	#[scope = "date-range-field"]
284	pub enum Part {
285	    Root,
286	    Label,
287	    StartField,
288	    Separator,
289	    EndField,
290	    Description,
291	    ErrorMessage,
292	    HiddenInput,
293	}
294	
295	/// API for the DateRangeField component.
296	pub struct Api<'a> {
297	    /// The state of the component.
298	    state: &'a State,
299	    /// The context of the component.
300	    ctx: &'a Context,
301	    /// The props of the component.
302	    props: &'a Props,
303	    /// The send function.
304	    send: &'a dyn Fn(Event),
305	}
306	
307	impl<'a> Api<'a> {
308	    // ── AttrMap getters ──────────────────────────────────────────────────
309	
310	    /// Attributes for the root element.
311	    pub fn root_attrs(&self) -> AttrMap {
312	        let mut attrs = AttrMap::new();
313	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
314	        attrs.set(scope_attr, scope_val);
315	        attrs.set(part_attr, part_val);
316	        attrs.set(HtmlAttr::Id, self.ctx.ids.id());
317	        attrs.set(HtmlAttr::Role, "group");
318	        attrs.set(HtmlAttr::Aria(AriaAttr::LabelledBy), self.ctx.ids.part("label"));
319	        attrs.set(HtmlAttr::Data("ars-state"), self.state_name());
320	        let mut described_by = Vec::new();
321	        if self.ctx.has_description { described_by.push(self.ctx.ids.part("description")); }
322	        if self.ctx.has_error_message { described_by.push(self.ctx.ids.part("error-message")); }
323	        if !described_by.is_empty() {
324	            attrs.set(HtmlAttr::Aria(AriaAttr::DescribedBy), described_by.join(" "));
325	        }
326	        if self.ctx.disabled {
327	            attrs.set_bool(HtmlAttr::Data("ars-disabled"), true);
328	        }
329	        if self.ctx.readonly {
330	            attrs.set_bool(HtmlAttr::Data("ars-readonly"), true);
331	        }
332	        if self.ctx.required {
333	            attrs.set(HtmlAttr::Aria(AriaAttr::Required), "true");
334	        }
335	        attrs
336	    }
337	
338	    /// Attributes for the label element.
339	    pub fn label_attrs(&self) -> AttrMap {
340	        let mut attrs = AttrMap::new();
341	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Label.data_attrs();
342	        attrs.set(scope_attr, scope_val);
343	        attrs.set(part_attr, part_val);
344	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("label"));
345	        attrs
346	    }
347	
348	    /// Attributes for the separator element.
349	    pub fn separator_attrs(&self) -> AttrMap {
350	        let mut attrs = AttrMap::new();
351	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Separator.data_attrs();
352	        attrs.set(scope_attr, scope_val);
353	        attrs.set(part_attr, part_val);
354	        attrs.set(HtmlAttr::Aria(AriaAttr::Hidden), "true");
355	        attrs
356	    }
357	
358	    /// The separator text between start and end fields (e.g., " – ").
359	    /// The adapter renders this as the text content of the Separator element.
360	    pub fn separator_text(&self) -> String {
361	        (self.ctx.messages.separator_text)(&self.ctx.locale)
362	    }
363	
364	    /// Screen reader description of the full date range (e.g., "March 1 to March 15").
365	    /// Returns `None` if no complete range is selected.
366	    /// The adapter can use this as an `aria-description` on the root or as a live announcement.
367	    pub fn range_description(&self) -> Option<String> {
368	        let range = self.ctx.value.get().as_ref()?;
369	        let start = format_date(&range.start, &self.ctx.format, &self.ctx.locale);
370	        let end = format_date(&range.end, &self.ctx.format, &self.ctx.locale);
371	        Some((self.ctx.messages.range_description)(&start, &end, &self.ctx.locale))
372	    }
373	
374	    /// Build DateField Props for the start date input.
375	    pub fn start_field_props(&self) -> date_field::Props {
376	        date_field::Props {
377	            id: self.ctx.ids.part("start"),
378	            value: self.ctx.value.get().as_ref().map(|r| Some(r.start.clone())),
379	            min: self.ctx.min.clone(),
380	            max: self.ctx.value.get().as_ref().map(|r| r.end.clone()),
381	            disabled: self.ctx.disabled,
382	            readonly: self.ctx.readonly,
383	            aria_label: Some((self.ctx.messages.start_label)(&self.ctx.locale)),
384	            force_leading_zeros: self.ctx.force_leading_zeros,
385	            ..Default::default()
386	        }
387	    }
388	
389	    /// Build DateField Props for the end date input.
390	    pub fn end_field_props(&self) -> date_field::Props {
391	        date_field::Props {
392	            id: self.ctx.ids.part("end"),
393	            value: self.ctx.value.get().as_ref().map(|r| Some(r.end.clone())),
394	            min: self.ctx.value.get().as_ref().map(|r| r.start.clone()),
395	            max: self.ctx.max.clone(),
396	            disabled: self.ctx.disabled,
397	            readonly: self.ctx.readonly,
398	            aria_label: Some((self.ctx.messages.end_label)(&self.ctx.locale)),
399	            force_leading_zeros: self.ctx.force_leading_zeros,
400	            ..Default::default()
401	        }
402	    }
403	
404	    /// Attributes for the description element.
405	    pub fn description_attrs(&self) -> AttrMap {
406	        let mut attrs = AttrMap::new();
407	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Description.data_attrs();
408	        attrs.set(scope_attr, scope_val);
409	        attrs.set(part_attr, part_val);
410	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("description"));
411	        attrs
412	    }
413	
414	    /// Attributes for the error message element.
415	    pub fn error_message_attrs(&self) -> AttrMap {
416	        let mut attrs = AttrMap::new();
417	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::ErrorMessage.data_attrs();
418	        attrs.set(scope_attr, scope_val);
419	        attrs.set(part_attr, part_val);
420	        attrs.set(HtmlAttr::Id, self.ctx.ids.part("error-message"));
421	        attrs.set(HtmlAttr::Role, "alert");
422	        attrs
423	    }
424	
425	    /// Attributes for the hidden input element.
426	    pub fn hidden_input_attrs(&self) -> AttrMap {
427	        let mut attrs = AttrMap::new();
428	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::HiddenInput.data_attrs();
429	        attrs.set(scope_attr, scope_val);
430	        attrs.set(part_attr, part_val);
431	        attrs.set(HtmlAttr::Type, "hidden");
432	        if let Some(ref name) = self.ctx.name {
433	            attrs.set(HtmlAttr::Name, name);
434	        }
435	        let iso_value = match self.ctx.value.get() {
436	            Some(range) => format!(
437	                "{}/{}",
438	                format_iso(&range.start),
439	                format_iso(&range.end),
440	            ),
441	            None => String::new(),
442	        };
443	        attrs.set(HtmlAttr::Value, iso_value);
444	        attrs
445	    }
446	
447	    /// Attributes for a separate hidden input carrying the start date.
448	    /// Only rendered when `start_name` is set on Props.
449	    pub fn start_hidden_input_attrs(&self) -> AttrMap {
450	        let mut attrs = AttrMap::new();
451	        attrs.set(HtmlAttr::Type, "hidden");
452	        if let Some(name) = &self.ctx.start_name {
453	            attrs.set(HtmlAttr::Name, name);
454	        }
455	        if let Some(range) = &self.ctx.value.get() {
456	            attrs.set(HtmlAttr::Value, format_iso(&range.start));
457	        }
458	        attrs
459	    }
460	
461	    /// Attributes for a separate hidden input carrying the end date.
462	    /// Only rendered when `end_name` is set on Props.
463	    pub fn end_hidden_input_attrs(&self) -> AttrMap {
464	        let mut attrs = AttrMap::new();
465	        attrs.set(HtmlAttr::Type, "hidden");
466	        if let Some(name) = &self.ctx.end_name {
467	            attrs.set(HtmlAttr::Name, name);
468	        }
469	        if let Some(range) = &self.ctx.value.get() {
470	            attrs.set(HtmlAttr::Value, format_iso(&range.end));
471	        }
472	        attrs
473	    }
474	
475	    // ── Convenience getters ─────────────────────────────────────────────
476	
477	    /// Get the selected range.
478	    pub fn selected_range(&self) -> Option<&DateRange> {
479	        self.ctx.value.get().as_ref()
480	    }
481	
482	    /// Whether either field is currently focused.
483	    pub fn is_focused(&self) -> bool {
484	        !matches!(self.state, State::Idle)
485	    }
486	
487	    /// Get the name of the current state.
488	    fn state_name(&self) -> &'static str {
489	        match self.state {
490	            State::Idle => "idle",
491	            State::StartFocused => "start-focused",
492	            State::EndFocused => "end-focused",
493	        }
494	    }
495	}
496	
497	impl ConnectApi for Api<'_> {
498	    type Part = Part;
499	
500	    fn part_attrs(&self, part: Part) -> AttrMap {
501	        match part {
502	            Part::Root => self.root_attrs(),
503	            Part::Label => self.label_attrs(),
504	            Part::StartField => self.start_field_props().into(), // delegated to DateField
505	            Part::Separator => self.separator_attrs(),
506	            Part::EndField => self.end_field_props().into(), // delegated to DateField
507	            Part::Description => self.description_attrs(),
508	            Part::ErrorMessage => self.error_message_attrs(),
509	            Part::HiddenInput => self.hidden_input_attrs(),
510	        }
511	    }
512	}
513	```
514	
515	## 2. Anatomy
516	
517	```text
518	DateRangeField (en-US)
519	└── Root                                  role="group"  data-ars-scope="date-range-field"
520	    ├── Label                             "Trip dates"
521	    ├── StartField (DateField)            role="group"  aria-label="Start date"
522	    │   ├── Segment (Month)               role="spinbutton"  aria-label="Month"
523	    │   ├── Literal "/"                   aria-hidden="true"
524	    │   ├── Segment (Day)                 role="spinbutton"  aria-label="Day"
525	    │   ├── Literal "/"                   aria-hidden="true"
526	    │   └── Segment (Year)               role="spinbutton"  aria-label="Year"
527	    ├── Separator                         " – "  aria-hidden="true"
528	    ├── EndField (DateField)              role="group"  aria-label="End date"
529	    │   ├── Segment (Month)               role="spinbutton"  aria-label="Month"
530	    │   ├── Literal "/"                   aria-hidden="true"
531	    │   ├── Segment (Day)                 role="spinbutton"  aria-label="Day"
532	    │   ├── Literal "/"                   aria-hidden="true"
533	    │   └── Segment (Year)               role="spinbutton"  aria-label="Year"
534	    ├── Description                       "Select check-in and check-out dates"
535	    ├── ErrorMessage                      role="alert"
536	    └── HiddenInput                       type="hidden"  value="2025-06-01/2025-06-15"
537	```
538	
539	| Part           | Element                 | Description                                                    |
540	| -------------- | ----------------------- | -------------------------------------------------------------- |
541	| `Root`         | `<div>`                 | `role="group"` — groups both fields; `aria-labelledby` → Label |
542	| `Label`        | `<label>`               | Shared label for the entire range                              |
543	| `StartField`   | _(DateField)_           | Start date segments (delegated to DateField)                   |
544	| `Separator`    | `<span>`                | `aria-hidden="true"` — visual separator (" -- " or "to")       |
545	| `EndField`     | _(DateField)_           | End date segments (delegated to DateField)                     |
546	| `Description`  | `<div>`                 | Optional help text; referenced by `aria-describedby`           |
547	| `ErrorMessage` | `<div role="alert">`    | Validation error text; announced immediately                   |
548	| `HiddenInput`  | `<input type="hidden">` | ISO 8601 range value for form submission                       |
549	
550	## 3. Accessibility
551	
552	### 3.1 ARIA Roles, States, and Properties
553	
554	| Part       | Role/Attribute     | Details                                                      |
555	| ---------- | ------------------ | ------------------------------------------------------------ |
556	| Root       | `role="group"`     | `aria-labelledby` points to Label                            |
557	| StartField | --                 | Delegates to DateField; each segment has `role="spinbutton"` |
558	| EndField   | --                 | Delegates to DateField; each segment has `role="spinbutton"` |
559	| Root       | `aria-disabled`    | Present when disabled                                        |
560	| Root       | `aria-readonly`    | Present when readonly                                        |
561	| Root       | `data-ars-invalid` | Present when validation fails                                |
562	| Root       | `aria-describedby` | Wired to Description and ErrorMessage part IDs               |
563	| Root       | `aria-required`    | Present when required                                        |
564	
565	### 3.2 Keyboard Interaction
566	
567	| Key        | Action                                                          |
568	| ---------- | --------------------------------------------------------------- |
569	| Tab        | Move focus from last segment of StartField to first of EndField |
570	| Shift+Tab  | Move focus from first segment of EndField to last of StartField |
571	| ArrowUp    | Increment focused segment value                                 |
572	| ArrowDown  | Decrement focused segment value                                 |
573	| ArrowLeft  | Move to previous segment (within current field)                 |
574	| ArrowRight | Move to next segment (within current field)                     |
575	
576	## 4. Internationalization
577	
578	### 4.1 Messages
579	
580	```rust
581	#[derive(Clone, Debug)]
582	pub struct Messages {
583	    /// Label for the start date field.
584	    pub start_label: MessageFn<dyn Fn(&Locale) -> String + Send + Sync>,
585	    /// Label for the end date field.
586	    pub end_label: MessageFn<dyn Fn(&Locale) -> String + Send + Sync>,
587	    /// Text displayed between start and end fields.
588	    pub separator_text: MessageFn<dyn Fn(&Locale) -> String + Send + Sync>,
589	    /// Description of the range for screen readers.
590	    pub range_description: MessageFn<dyn Fn(&str, &str, &Locale) -> String + Send + Sync>,
591	}
592	
593	impl Default for Messages {
594	    fn default() -> Self {
595	        Self {
596	            start_label: MessageFn::static_str("Start date"),
597	            end_label: MessageFn::static_str("End date"),
598	            separator_text: MessageFn::static_str(" \u{2013} "),
599	            range_description: MessageFn::new(|start, end, _locale| {
600	                format!("{} to {}", start, end)
601	            }),
602	        }
603	    }
604	}
605	
606	impl ComponentMessages for Messages {}
607	```
608	
609	- Label text and separator are consumer-overridable via Messages.
610	- `data-ars-state` values are stable API tokens, not localized.
611	- RTL: segment ordering within each field follows locale conventions (delegated to DateField).
612	
613	## 5. Form Integration
614	
615	- Hidden `<input>` submits the current range in ISO 8601 interval format (`YYYY-MM-DD/YYYY-MM-DD`).
616	- `name` attribute is set from Props.
617	- Reset restores `default_value`.
618	- Validation states (`valid`, `invalid`) reflected via `data-ars-invalid` on Root.
619	- `aria-describedby` wires to Description and ErrorMessage parts.
620	- `aria-required` set when `required` is true.
621	- Disabled/readonly propagation from form context per `07-forms.md` S15.
622	
623	## 6. Library Parity
624	
625	> Compared against: React Aria (`DateRangePicker` field-only aspects).
626	
627	React Aria does not have a standalone `DateRangeField` component separate from `DateRangePicker`. The closest equivalent is the inline portion of `DateRangePicker` (two `DateInput` slots without the popover). ars-ui separates the range field into its own component for composability.
628	
629	### 6.1 Props
630	
631	| Feature               | ars-ui                | React Aria                  | Notes                          |
632	| --------------------- | --------------------- | --------------------------- | ------------------------------ |
633	| Controlled range      | `value`               | `value` (RangeValue)        | Equivalent                     |
634	| Default range         | `default_value`       | `defaultValue`              | Equivalent                     |
635	| Min/max               | `min`, `max`          | `minValue`, `maxValue`      | Equivalent                     |
636	| Disabled              | `disabled`            | `isDisabled`                | Equivalent                     |
637	| Read-only             | `readonly`            | `isReadOnly`                | Equivalent                     |
638	| Required              | `required`            | `isRequired`                | Equivalent                     |
639	| Locale                | `locale`              | -- (context)                | Equivalent                     |
640	| Name                  | `name`                | `startName`, `endName`      | React Aria uses separate names |
641	| Force leading zeros   | `force_leading_zeros` | `shouldForceLeadingZeros`   | Equivalent                     |
642	| Allows non-contiguous | --                    | `allowsNonContiguousRanges` | React Aria feature             |
643	| Start/end names       | --                    | `startName`, `endName`      | Separate form field names      |
644	
645	**Gaps:** None.
646	
647	### 6.2 Anatomy
648	
649	| Part          | ars-ui                   | React Aria                 | Notes                          |
650	| ------------- | ------------------------ | -------------------------- | ------------------------------ |
651	| Root          | `Root`                   | `DateRangePicker`          | Equivalent                     |
652	| Label         | `Label`                  | `Label`                    | Equivalent                     |
653	| Start field   | `StartField` (DateField) | `DateInput` (slot="start") | Equivalent                     |
654	| Separator     | `Separator`              | --                         | ars-ui explicit separator part |
655	| End field     | `EndField` (DateField)   | `DateInput` (slot="end")   | Equivalent                     |
656	| Description   | `Description`            | `Text` (slot)              | Equivalent                     |
657	| Error message | `ErrorMessage`           | `FieldError`               | Equivalent                     |
658	| Hidden input  | `HiddenInput`            | --                         | ars-ui form integration        |
659	
660	**Gaps:** None.
661	
662	### 6.3 Events
663	
664	| Callback     | ars-ui                                | React Aria      | Notes      |
665	| ------------ | ------------------------------------- | --------------- | ---------- |
666	| Range change | `StartValueChange` / `EndValueChange` | `onChange`      | Equivalent |
667	| Focus        | `FocusStart` / `FocusEnd`             | `onFocusChange` | Equivalent |
668	| Blur         | `BlurAll`                             | `onBlur`        | Equivalent |
669	
670	**Gaps:** None.
671	
672	### 6.4 Features
673	
674	| Feature                    | ars-ui | React Aria |
675	| -------------------------- | ------ | ---------- |
676	| Two-field range input      | Yes    | Yes        |
677	| Range normalization        | Yes    | Yes        |
678	| Cross-field tab navigation | Yes    | Yes        |
679	| Hidden form input          | Yes    | No         |
680	| Separate form names        | No     | Yes        |
681	
682	**Gaps:** None.
683	
684	### 6.5 Summary
685	
686	- **Overall:** Full parity.
687	- **Divergences:** React Aria bundles the range field into `DateRangePicker`; ars-ui separates it for composability. ars-ui adds a `Separator` part and hidden form input.
688	- **Recommended additions:** None.
