265	pub(crate) fn bounded_days_in_month(
266	    calendar: CalendarSystem,
267	    year: i32,
268	    month: u8,
269	    era: Option<&str>,
270	) -> Option<u8> {
271	    match calendar {
272	        CalendarSystem::Japanese => {
273	            let boundary = japanese_era_boundary(era?)?;
274	
275	            // Japanese public dates store `year` as year-in-era, so convert it
276	            // back to the underlying Gregorian year before using Gregorian
277	            // month-length rules.
278	            let absolute_year = boundary.start_year.checked_add(year)?.checked_sub(1)?;
279	
280	            let mut max_day = gregorian_days_in_month(absolute_year, month);
281	
282	            if let Some((end_year, end_month, end_day)) = boundary.end {
283	                // The final month of a historical era may end early, e.g.
284	                // Heisei ends on 2019-04-30 instead of the full month.
285	                let max_year = end_year - boundary.start_year + 1;
286	
287	                if year == max_year && month == end_month {
288	                    max_day = max_day.min(end_day);
289	                }
290	            }
291	
292	            Some(max_day)
293	        }
294	        _ => None,
295	    }
296	}
