349	/// Converts an ISO date to a day count relative to `0001-01-01`.
350	#[must_use]
351	#[cfg(test)]
352	pub(crate) fn iso_to_epoch_days(year: i32, month: u8, day: u8) -> i64 {
353	    // Shift Jan/Feb to the end of the previous year so the leap-day correction
354	    // can be handled uniformly with a March-based year.
355	    let year_adjustment = (14 - i64::from(month)) / 12;
356	
357	    let march_based_year = i64::from(year) + 4800 - year_adjustment;
358	
359	    let march_based_month = i64::from(month) + 12 * year_adjustment - 3;
360	
361	    // The remaining constants are from the standard Gregorian civil-date to
362	    // Julian day transform:
363	    // - `153` groups months into a repeating March-based pattern
364	    // - `32_045` removes the Julian-day epoch bias
365	    // - `GREGORIAN_JDN_OFFSET` rebases onto `0001-01-01 = 0`
366	    i64::from(day)
367	        + (153 * march_based_month + 2) / 5
368	        + 365 * march_based_year
369	        + march_based_year / 4
370	        - march_based_year / 100
371	        + march_based_year / 400
372	        - 32_045
373	        - GREGORIAN_JDN_OFFSET
374	}
375	
376	/// Converts an epoch-day count back to an ISO date.
377	#[must_use]
378	#[cfg(test)]
379	pub(crate) const fn epoch_days_to_iso(epoch_days: i64) -> (i32, u8, u8) {
380	    // First move back into the Julian-day numbering domain expected by the
381	    // inverse civil-date algorithm.
382	    let julian_day = epoch_days + GREGORIAN_JDN_OFFSET + 32_044;
383	
384	    // Split the day number across the Gregorian 400-year cycle (`146_097`
385	    // days), then the 4-year subcycle (`1_461` days).
386	    let century_cycles = (4 * julian_day + 3) / 146_097;
387	
388	    let days_of_century = julian_day - (146_097 * century_cycles) / 4;
389	
390	    let quad_year_cycles = (4 * days_of_century + 3) / 1_461;
391	
392	    let day_of_year_block = days_of_century - (1_461 * quad_year_cycles) / 4;
393	
394	    // `153` again encodes the March-based month pattern used by the forward
395	    // conversion. Converting back from that index yields the ISO month/year.
396	    let month_index = (5 * day_of_year_block + 2) / 153;
397	
398	    let day = (day_of_year_block - (153 * month_index + 2) / 5 + 1) as u8;
399	
400	    let month = (month_index + 3 - 12 * (month_index / 10)) as u8;
401	
402	    let year = (100 * century_cycles + quad_year_cycles - 4800 + month_index / 10) as i32;
403	
404	    (year, month, day)
405	}
