    let built = Props::new()
        .id("trip")
        .value(Some(range(date(2025, 6, 1), date(2025, 6, 15))))
        .default_value(Some(range(date(2025, 1, 1), date(2025, 1, 2))))
        .min(Some(date(2024, 1, 1)))
