/// Applies a start-date change, coordinating with the existing end date.
fn apply_start_change(ctx: &mut Context, start: Option<CalendarDate>) {
    let existing_end = ctx.value.get().as_ref().map(|range| range.end.clone());

    match (start, existing_end) {
        (Some(start), Some(end)) => {
            if let Some(range) = DateRange::normalized(start, end) {
                ctx.value.set(Some(range));
            }
        }
        // Only the start is set; no complete range yet. The range completes
        // when the end is also provided.
        (Some(_), None) => {}
        (None, _) => ctx.value.set(None),
    }
}

/// Applies an end-date change, coordinating with the existing start date.
fn apply_end_change(ctx: &mut Context, end: Option<CalendarDate>) {
    let existing_start = ctx.value.get().as_ref().map(|range| range.start.clone());

    match (existing_start, end) {
        (Some(start), Some(end)) => {
            if let Some(range) = DateRange::normalized(start, end) {
                ctx.value.set(Some(range));
            }
        }
        // Only the end is set; no complete range yet.
        (None, Some(_)) => {}
        (_, None) => ctx.value.set(None),
    }
}

